# CMB-0040B_INFRASTRUCTURE.py
from __future__ import annotations

import re
import urllib.request

BASE_URL = 'https://raw.githubusercontent.com/gear66me-ui/CMB-Plank/main/CMB-0040A_INFRASTRUCTURE.py'

with urllib.request.urlopen(BASE_URL, timeout=60) as response:
    source = response.read().decode('utf-8')

source = re.sub(r"VERSION\s*=\s*['\"]CMB-[^'\"]+['\"]", "VERSION = 'CMB-0040B'", source, count=1)
source = source.replace("radius_arcsec = max(30.0, float(fov.value) * 3600.0 / 6.0)", "radius_arcsec = max(180.0, float(fov.value) * 3600.0)")
source = source.replace("set_status('Searching inclusive catalog stack', parsed + '<br>Trying NED, SIMBAD, and broad CDS/VizieR cone searches…', '#2196f3')", "set_status('Searching inclusive catalog stack', parsed + '<br>Trying NED, SIMBAD, broad VizieR, and survey-family discovery for GOODS/CANDELS/JADES/HST/Gaia/2MASS/WISE/GALEX/X-ray catalogs…', '#2196f3')")

start = source.index('def nearest_vizier(coord, radius_arcsec):')
end = source.index('\ndef object_details(obj):', start)
new_func = '''def nearest_vizier(coord, radius_arcsec):\n    rows = []\n    radius = radius_arcsec * u.arcsec\n    seen = set()\n\n    def add_from_result(result, label):\n        for table in result:\n            meta = getattr(table, 'meta', {}) or {}\n            cat = meta.get('name') or meta.get('ID') or getattr(table, 'name', 'VizieR') or label\n            description = meta.get('description', '')\n            for row in table[:60]:\n                c = coord_from_row(row, table)\n                sep = safe_float(row['_r']) if '_r' in getattr(table, 'colnames', []) else np.nan\n                if c is not None:\n                    sep = coord.separation(c).arcsec\n                    ra = c.ra.deg\n                    dec = c.dec.deg\n                else:\n                    ra = np.nan\n                    dec = np.nan\n                obj_id = object_name_from_row(row)\n                key = (str(cat), obj_id, round(sep if np.isfinite(sep) else 999999, 3))\n                if key in seen:\n                    continue\n                seen.add(key)\n                rows.append({\n                    'Object ID': obj_id,\n                    'Catalog': f'VizieR {cat}',\n                    'RA': ra,\n                    'Dec': dec,\n                    'Angular separation (arcsec)': sep,\n                    'Redshift': safe_float(first_value(row, ['z', 'Z', 'redshift', 'zphot', 'zspec', 'z_phot', 'z_spec'])),\n                    'Type': description[:90] if description else label,\n                })\n\n    direct_batches = [\n        ['I/355/gaiadr3', 'I/350/gaiaedr3', 'I/345/gaia2'],\n        ['II/246/out', 'II/328/allwise', 'II/363/unwise', 'II/311/wise'],\n        ['II/312/ais', 'II/335/galex_ais', 'II/335/galex_mis'],\n        ['IX/57/xmm4dr13', 'IX/58/2sxps', 'IX/59/csc2master'],\n        ['J/ApJS/207/24', 'J/ApJS/206/8', 'J/ApJS/214/24', 'J/ApJ/754/83'],\n        ['J/ApJS/229/32', 'J/ApJS/258/11', 'J/AJ/151/134', 'J/ApJ/837/97'],\n    ]\n    for cats in direct_batches:\n        try:\n            v = Vizier(columns=['*', '+_r'], row_limit=80)\n            v.TIMEOUT = 60\n            add_from_result(v.query_region(coord, radius=radius, catalog=cats), ', '.join(cats))\n        except Exception as exc:\n            STATE['warnings'].append(f'VizieR batch failed: {exc}')\n\n    keywords = ['GOODS-S', 'GOODS', 'CANDELS', 'JADES', '3D-HST', 'HUDF', 'Hubble Source Catalog', 'Chandra Deep Field South', 'CDFS', 'Chandra', 'XMM', 'eROSITA', 'GALEX', 'WISE', '2MASS', 'Spitzer', 'ALMA GOODS']\n    keys = []\n    for keyword in keywords:\n        try:\n            found = Vizier.find_catalogs(keyword, max_catalogs=30)\n            for key in found.keys():\n                if key not in keys:\n                    keys.append(key)\n        except Exception as exc:\n            STATE['warnings'].append(f'Catalog discovery failed for {keyword}: {exc}')\n    for i in range(0, min(len(keys), 160), 20):\n        try:\n            v = Vizier(columns=['*', '+_r'], row_limit=60)\n            v.TIMEOUT = 60\n            add_from_result(v.query_region(coord, radius=radius, catalog=keys[i:i+20]), 'survey-family discovery')\n        except Exception as exc:\n            STATE['warnings'].append(f'VizieR discovered batch failed: {exc}')\n        if len(rows) > 250:\n            break\n\n    if not rows:\n        try:\n            v = Vizier(columns=['*', '+_r'], row_limit=100)\n            v.TIMEOUT = 60\n            add_from_result(v.query_region(coord, radius=radius), 'all VizieR/CDS')\n        except Exception as exc:\n            STATE['warnings'].append(f'All-catalog VizieR fallback failed: {exc}')\n    return rows\n\n'''
source = source[:start] + new_func + source[end+1:]

compile(source, 'CMB-0040B_GENERATED.py', 'exec')
exec(compile(source, 'CMB-0040B_GENERATED.py', 'exec'), globals())
